class Graph:
    def __init__(self):
        self._start_node = None  # dummy node
        self._next_node = None  # next node in the graph
        self._end_node = None

    def start(self, node):
        self._start_node = node
        if self._next_node is None:
            self._next_node = node
        else:
            raise ValueError("Node '{node}' does not exist in the graph.")

    def end(self, node):
        self._end_node = node
        if self._next_node is None or self._next_node == self._start_node:
            self._next_node = node
        else:
            raise ValueError("All nodes in the graph have ended with a new node that does not exist in the end node.")

    def get(self, node):
        if node == self._start_node:
            return self._end_node  # only the first node is considered
        elif node == self._next_node:
            return self._start_node

        raise ValueError("Node '{node}' does not exist in the graph.")

    def sum_nodes(self):
        nodes = self._start_node.extend(self._next_node.extend([node for node, self._next_node in self._end_node.items()]))
        return sum(nodes)
